descriptor.templateCss:
.ed-card {
  font-family: 'Roboto', sans-serif;
  background: linear-gradient(145deg, #16213e 0%, #0f3460 100%);
  color: #ffffff;
  border-radius: 16px;
  padding: 20px;
  box-sizing: border-box;
  height: 100%;
  display: flex;
  flex-direction: column;
  gap: 14px;
}
.ed-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.ed-title { font-size: 18px; font-weight: 600; }
.ed-status {
  font-size: 12px;
  font-weight: 700;
  padding: 4px 12px;
  border-radius: 20px;
  background: #2ecc71;
  color: #fff;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.ed-status.limited { background: #f39c12; }
.ed-status.full { background: #e74c3c; }

.ed-price-box {
  background: rgba(255,255,255,0.08);
  border-radius: 12px;
  padding: 14px;
  text-align: center;
}
.ed-price-label { display:block; font-size: 12px; opacity: 0.7; }
.ed-price { font-size: 40px; font-weight: 700; color: #ffd166; }
.ed-price-unit { font-size: 13px; opacity: 0.7; }

.ed-spaces { text-align: center; }
.ed-spaces-num { font-size: 32px; font-weight: 700; color: #4dd0e1; }
.ed-spaces-label { font-size: 12px; opacity: 0.7; }

.ed-bar-top {
  display: flex; justify-content: space-between;
  font-size: 12px; opacity: 0.85; margin-bottom: 4px;
}
.ed-bar-bg {
  background: rgba(255,255,255,0.15);
  border-radius: 20px; height: 12px; overflow: hidden;
}
.ed-bar-fill {
  height: 100%; width: 0%;
  background: linear-gradient(90deg, #2ecc71, #f39c12, #e74c3c);
  border-radius: 20px;
  transition: width 0.4s ease;
}

.ed-message {
  text-align: center; font-size: 14px;
  padding: 8px; background: rgba(255,255,255,0.06);
  border-radius: 8px;
}
.ed-footer {
  display: flex; justify-content: space-between;
  font-size: 12px; opacity: 0.8; margin-top: auto;
}
.ed-book.yes { color: #2ecc71; font-weight: 600; }
.ed-book.no { color: #e74c3c; font-weight: 600; }
.ed-ev-box{display:flex;align-items:center;gap:6px;padding:6px 12px;background:rgba(0,188,212,.1);border-radius:6px;margin:4px 0}.ed-ev-label{color:#00bcd4;font-size:11px;font-weight:500;flex:1}.ed-ev-price{font-size:18px;font-weight:700;color:#00bcd4}.ed-ev-unit{color:#888;font-size:11px}

descriptor.controllerScript:
self.onInit = function() {};

self.onDataUpdated = function() {
  var data = self.ctx.data;
  var vals = {};

  for (var i = 0; i < data.length; i++) {
    var key = data[i].dataKey.name;
    var arr = data[i].data;
    if (arr && arr.length > 0) {
      vals[key] = arr[arr.length - 1][1];
    }
  }

  var $ = function(id) { return self.ctx.$container.find('#' + id); };

  if (vals.current_price_per_hour != null) {
    $('ed-price').text(Number(vals.current_price_per_hour).toFixed(2));
  }
  if (vals.free_spaces != null) {
    $('ed-free').text(vals.free_spaces);
  }
  if (vals.occupancy_rate != null) {
    var occ = Math.round(Number(vals.occupancy_rate));
    $('ed-occ-text').text(occ + '%');
    $('ed-bar').css('width', occ + '%');
  }
  if (vals.display_status != null) {
    var st = String(vals.display_status);
    var el = $('ed-status');
    el.text(st).removeClass('limited full');
    if (st === 'LIMITED') el.addClass('limited');
    else if (st === 'FULL') el.addClass('full');
  }
  if (vals.display_message != null) {
    $('ed-msg').text(vals.display_message);
  }
  if (vals.booking_available != null) {
    var bookable = (vals.booking_available === true || vals.booking_available === 'true');
    var b = $('ed-book');
    b.text(bookable ? '✓ Booking available' : '✗ Booking closed')
     .removeClass('yes no')
     .addClass(bookable ? 'yes' : 'no');
  }
  if (vals.evChargingPrice != null) {
    $('ed-ev-price').text(Number(vals.evChargingPrice).toFixed(2));
  }
  if (vals.forecast_next_hour_price != null) {
    var fLabel = vals.forecast_label ? vals.forecast_label + ': ' : 'Next hour: ';
    $('ed-forecast').text('📈 ' + fLabel + Number(vals.forecast_next_hour_price).toFixed(2) + ' €/h');
  }
};

self.onResize = function() {};
self.onDestroy = function() {};

